{
  "grammar": [
    {
      "pattern": "Subject + 把 + Object + 帶來 / 帶去 + Location",
      "structure": ["Subject", "把", "Object", "帶來/帶去", "Location"],
      "explanation_en": "Use 帶來 to indicate bringing something toward the speaker's location, and 帶去 to indicate taking something away from the speaker's location.",
      "title": "Bringing and Taking with 帶來 and 帶去",
      "meaning": "Indicates movement of an object toward or away from the speaker.",
      "when_to_use": ["When you bring something to where the speaker is", "When you take something to another place"],
      "when_not_to_use": ["Do not use for people moving themselves", "Do not confuse with 拿來/拿去 which implies carrying by hand"],
      "pragmatic_notes": "In Taiwan, 帶來 is common when offering food or gifts to someone present; 帶去 is used when planning to take something to a different location.",
      "word_order_notes": "The object must come before 帶來/帶去, and the location is optional but typically placed after.",
      "english_contrast": "English uses 'bring' and 'take' without a directional suffix; Chinese requires 來/去 to show direction relative to speaker.",
      "korean_contrast": "Korean uses '가져오다' (bring) and '가져가다' (take), similar to Chinese 帶來/帶去.",
      "negative_examples": [
        {
          "text": "我帶來書這裡。",
          "error": "Word order is wrong; 這裡 should come after 帶來."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我帶去書你。",
          "error": "Missing 把 and incorrect object placement."
        }
      ],
      "transformation_drills": ["Change '我帶咖啡來' to '我把咖啡帶來'", "Change '他帶書去學校' to '他把書帶去學校'"],
      "production_drills": ["Say you bring tea to a friend's house", "Say you take a book to the library"],
      "common_error_patterns": ["Omitting 把 when object is specific", "Using 帶來 when speaker is not at the destination"],
      "repair_feedback": {
        "word_order": "Remember: 把 + object + 帶來/帶去 + location.",
        "politeness": "Use 請 before the verb for polite requests.",
        "vocabulary": "Use 帶來 for bringing toward you, 帶去 for taking away."
      }
    },
    {
      "pattern": "Subject + 回來 / 回去 + (Location)",
      "structure": ["Subject", "回來/回去", "Location"],
      "explanation_en": "Use 回來 to indicate returning to the speaker's current location, and 回去 to indicate returning to a place away from the speaker.",
      "title": "Coming Back and Going Back with 回來 and 回去",
      "meaning": "Indicates returning to a location relative to the speaker.",
      "when_to_use": ["When you return to where the speaker is", "When you go back to another place"],
      "when_not_to_use": ["Do not use for first-time arrivals", "Do not confuse with 來/去 which imply initial movement"],
      "pragmatic_notes": "In Taiwan, 回來 is often used when someone returns home or to the office; 回去 is used when leaving the current place to go back elsewhere.",
      "word_order_notes": "Location is optional and placed after 回來/回去.",
      "english_contrast": "English uses 'come back' and 'go back' similarly, but Chinese requires the directional complement attached to the verb.",
      "korean_contrast": "Korean uses '돌아오다' (come back) and '돌아가다' (go back), matching Chinese 回來/回去.",
      "negative_examples": [
        {
          "text": "我回去家。",
          "error": "家 should be placed after 回去, but 回去 already implies home; use 回家 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他回來從學校。",
          "error": "從 should be before 學校, not after 回來."
        }
      ],
      "transformation_drills": ["Change '我回台灣' to '我回來台灣'", "Change '他去公司' to '他回去公司'"],
      "production_drills": ["Say you come back to Taipei", "Say you go back to the office"],
      "common_error_patterns": ["Using 回來 when the speaker is not at the destination", "Omitting 回 and using only 來/去"],
      "repair_feedback": {
        "word_order": "Place 回來/回去 after the subject and before location.",
        "politeness": "Use 請 before the verb for polite requests.",
        "vocabulary": "Use 回來 for returning to speaker's location, 回去 for returning elsewhere."
      }
    },
    {
      "pattern": "Subject + 把 + Object + 拿來 / 拿去 + Location",
      "structure": ["Subject", "把", "Object", "拿來/拿去", "Location"],
      "explanation_en": "Use 拿來 to indicate bringing an object by hand toward the speaker, and 拿去 to indicate taking an object by hand away from the speaker.",
      "title": "Bringing and Taking by Hand with 拿來 and 拿去",
      "meaning": "Indicates manual carrying of an object toward or away from the speaker.",
      "when_to_use": ["When you carry something to where the speaker is", "When you carry something to another place"],
      "when_not_to_use": ["Do not use for large objects that are not carried by hand", "Do not confuse with 帶來/帶去 which imply accompanying an object"],
      "pragmatic_notes": "In Taiwan, 拿來 is common in shops when asking for an item; 拿去 is used when handing something to someone else.",
      "word_order_notes": "The object must come before 拿來/拿去, and the location is optional but typically placed after.",
      "english_contrast": "English uses 'bring' and 'take' without specifying 'by hand'; Chinese 拿來/拿去 emphasizes manual carrying.",
      "korean_contrast": "Korean uses '가져오다' and '가져가다' similarly, but without the hand-specific nuance.",
      "negative_examples": [
        {
          "text": "我拿來水你。",
          "error": "你 should be replaced with 給你 or placed after 拿來."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他拿去書圖書館。",
          "error": "Missing 把 and incorrect object placement."
        }
      ],
      "transformation_drills": ["Change '我拿咖啡來' to '我把咖啡拿來'", "Change '他拿書去教室' to '他把書拿去教室'"],
      "production_drills": ["Say you bring a cup of water to the table", "Say you take a book to the library"],
      "common_error_patterns": ["Omitting 把 when object is specific", "Using 拿來 when the object is not carried by hand"],
      "repair_feedback": {
        "word_order": "Remember: 把 + object + 拿來/拿去 + location.",
        "politeness": "Use 請 before the verb for polite requests.",
        "vocabulary": "Use 拿來 for bringing by hand toward you, 拿去 for taking by hand away."
      }
    }
  ]
}
